from dataclasses import dataclass
from datetime import date

@dataclass
class CVERecord:
    cve_id: str
    package: str
    installed_version: str
    fixed_version: str
    cvss_score: float
    published_date: date
    sla_days: int   # Days within which patch is required

    @property
    def days_open(self) -> int:
        return (date.today() - self.published_date).days

    @property
    def is_sla_breached(self) -> bool:
        return self.days_open > self.sla_days

    @property
    def severity(self) -> str:
        if self.cvss_score >= 9.0:
            return "CRITICAL"
        if self.cvss_score >= 7.0:
            return "HIGH"
        if self.cvss_score >= 4.0:
            return "MODERATE"
        return "LOW"

# Patch SLA by severity (PCI DSS-aligned)
PATCH_SLA: dict[str, int] = {
    "CRITICAL": 30,
    "HIGH": 30,
    "MODERATE": 90,
    "LOW": 180,
}

def scan_ai_dependencies(sbom: list[dict]) -> list[CVERecord]:
    """
    Parse a Software Bill of Materials (SBOM) and return CVE records
    for known vulnerabilities in AI/ML dependencies.
    SBOM format: [{package, version, cves: [{id, cvss, published, fixed_version}]}]
    """
    records: list[CVERecord] = []
    for component in sbom:
        pkg = component["package"]
        ver = component["version"]
        for cve in component.get("cves", []):
            severity = "CRITICAL" if cve["cvss"] >= 9.0 else (
                "HIGH" if cve["cvss"] >= 7.0 else
                "MODERATE" if cve["cvss"] >= 4.0 else "LOW"
            )
            records.append(CVERecord(
                cve_id=cve["id"],
                package=pkg,
                installed_version=ver,
                fixed_version=cve.get("fixed_version", "unknown"),
                cvss_score=cve["cvss"],
                published_date=date.fromisoformat(cve["published"]),
                sla_days=PATCH_SLA[severity],
            ))
    return records
